export enum ClassLabel {
  HATE_SPEECH = 'Hate Speech',
  OFFENSIVE_LANGUAGE = 'Offensive Language',
  NORMAL = 'Normal Speech'
}

export interface PredictionResult {
  label: ClassLabel;
  confidence: number;
  explanation: string;
}

export interface DatasetRow {
