  const [error, setError] = useState<string | null>(null);

  const handlePredict = async () => {
    if (!inputText.trim()) return;

    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const prediction = await analyzeText(inputText);
      setResult(prediction);
    } catch (err: any) {
      console.error(err);
