    { id: 'how-it-works', label: 'Methodology', icon: <BookOpen className="w-5 h-5" />, description: 'OLS Pipeline' },
    { id: 'dataset', label: 'Dataset', icon: <Database className="w-5 h-5" />, description: 'Data Analysis' },
