import { GoogleGenAI, Type } from "@google/genai";

export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    // Standard CORS headers
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type',
    };

    // Handle Preflight requests
    if (request.method === 'OPTIONS') {
      return new Response(null, { headers: corsHeaders });
    }

    // --- API Route: Handle Prediction Requests ---
    if (url.pathname === '/api/predict' && request.method === 'POST') {
      try {
        // 1. Securely access the API Key
        const apiKey = env.API_KEY;
        if (!apiKey) {
          console.error("API_KEY is missing in environment variables.");
          return new Response(JSON.stringify({ 
            error: 'Configuration Error: API_KEY is missing in Cloudflare settings.' 
          }), {
            status: 500,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        // 2. Parse User Input
        let body;
        try {
          body = await request.json();
        } catch (e) {
          return new Response(JSON.stringify({ error: "Invalid JSON body" }), {
             status: 400,
             headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        const { text, audio } = body;

        if (!text && !audio) {
          return new Response(JSON.stringify({ error: "Input text or audio is required." }), {
            status: 400,
            headers: { ...corsHeaders, 'Content-Type': 'application/json' }
          });
        }

        // 3. Call Gemini API
        const ai = new GoogleGenAI({ apiKey });

        let contents = [];

        if (audio) {
            // Multimodal Request (Audio + Instructions)
            // Ensure mimeType is valid. If frontend sent empty string, fallback to a safe default but log it.
            const mimeType = audio.mimeType || "audio/webm";

            contents = [
                {
                    inlineData: {
                        mimeType: mimeType,
                        data: audio.data
                    }
                },
                {
                    text: `You are an expert Hate Speech Detection system.

                    TASK:
                    1. Listen to the audio provided.
                    2. Transcribe the speech exactly as spoken into the 'transcription' field.
                    3. Analyze the sentiment, tone, and vocabulary.
                    4. Classify it into exactly one of these three categories:
                       - "Hate Speech" (Direct attacks, slurs, threats based on protected characteristics)
                       - "Offensive Language" (Vulgar, rude, insults, profanity, but NOT hate speech)
                       - "Normal Speech" (Neutral, benign, or positive)

                    IMPORTANT:
                    - If the audio is silent or unintelligible, return "Normal Speech" and explain that no speech was detected.
                    - If the audio is short/cut off but contains a slur, classify based on available context.

                    Return JSON with 'label', 'confidence' (0.0-1.0), 'explanation', and 'transcription'.`
                }
            ];
        } else {
            // Text Request
            contents = [
                {
                    text: `Act as a refined Machine Learning classifier trained on the Davidson Hate Speech Dataset.
                    Your task is to classify the provided text into one of three categories:
                    1. Hate Speech (Racist, sexist, or directed hate towards a protected group)
                    2. Offensive Language (Vulgar, rude, or inappropriate, but not hate speech)
                    3. Normal Speech (Neutral, positive, or benign)

                    If the text is nonsense, too short, or meaningless (like "kc", "asdf"), classify it as "Normal Speech" with low confidence.

                    Analyze the text accurately. Provide a confidence score (0.0 to 1.0) and a brief academic explanation.

                    Text to analyze: "${text}"`
                }
            ];
        }

        const response = await ai.models.generateContent({
          model: "gemini-3-flash-preview", // Supports multimodal
          contents: contents,
          config: {
            thinkingConfig: { thinkingBudget: 0 },
            responseMimeType: "application/json",
            // We use BLOCK_NONE to ensure the model actually processes the offensive content for classification
            // rather than refusing to answer.
            safetySettings: [
              { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_NONE" },
              { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_NONE" },
              { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_NONE" },
              { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_NONE" }
            ],
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                label: {
                  type: Type.STRING,
                  enum: [
                    'Hate Speech',
                    'Offensive Language',
                    'Normal Speech'
                  ],
                },
                confidence: {
                  type: Type.NUMBER,
                  description: "Confidence score between 0 and 1",
                },
                explanation: {
                  type: Type.STRING,
                  description: "A brief sentence explaining the classification logic.",
                },
                transcription: {
                  type: Type.STRING,
                  description: "The text extracted from the audio (if audio provided), or the input text.",
                }
              },
              required: ["label", "confidence", "explanation"],
            },
          },
        });

        const resultJSON = response.text;

        if (!resultJSON) {
           throw new Error("Model returned empty response.");
        }

        return new Response(resultJSON, {
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });

      } catch (error) {
        console.error("Worker Execution Error:", error);
        return new Response(JSON.stringify({ 
          error: `Worker Error: ${error.message || error.toString()}` 
        }), {
          status: 500,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' }
        });
      }
    }

    // --- Static Asset Serving ---
    try {
      if (url.pathname === '/') {
        const response = await env.ASSETS.fetch(new Request(`${url.origin}/index.html`, request));
        if (response.status === 200) return response;
      }

      let response = await env.ASSETS.fetch(request);

      if (response.status === 404 && !url.pathname.includes('.')) {
        response = await env.ASSETS.fetch(new Request(`${url.origin}/index.html`, request));
      }

      return response;
    } catch (e) {
      return new Response("Not Found", { status: 404 });
    }
  },
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, AlertTriangle, CheckCircle, Info, Loader2, Mic, Square, Trash2, Play, Volume2, Activity, Lock, RefreshCw, MessageSquare } from 'lucide-react';
import { analyzeText } from '../services/geminiService';
import { PredictionResult, ClassLabel } from '../types';

// Add SpeechRecognition types
declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

const Demo: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [result, setResult] = useState<PredictionResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Audio State
  const [isRecording, setIsRecording] = useState(false);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const [mimeType, setMimeType] = useState<string>('audio/webm'); // Default, will update

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const recognitionRef = useRef<any>(null); // For Speech Recognition
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationFrameRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      cleanupAudio();
    };
  }, []);

  const cleanupAudio = () => {
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    if (timerRef.current) clearInterval(timerRef.current);
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      audioContextRef.current.close();
    }
    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }
  };

  // Visualizer function
  const drawVisualizer = () => {
    if (!canvasRef.current || !analyserRef.current) return;

    const canvas = canvasRef.current;
    const canvasCtx = canvas.getContext('2d');
    const analyser = analyserRef.current;

    if (!canvasCtx) return;

    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const draw = () => {
      animationFrameRef.current = requestAnimationFrame(draw);
      analyser.getByteFrequencyData(dataArray);

      canvasCtx.clearRect(0, 0, canvas.width, canvas.height);

      const barWidth = (canvas.width / bufferLength) * 2.5;
      let barHeight;
      let x = 0;

      for (let i = 0; i < bufferLength; i++) {
        barHeight = dataArray[i] / 2;

        // Gradient color based on height
        const r = barHeight + 25 * (i / bufferLength);
        const g = 250 * (i / bufferLength);
        const b = 50;

        canvasCtx.fillStyle = `rgb(${r},${g},${b})`;
        canvasCtx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);

        x += barWidth + 1;
      }
    };

    draw();
  };

  const getSupportedMimeType = () => {
    const types = [
      'audio/webm;codecs=opus',
      'audio/webm',
      'audio/mp4', // Safari
      'audio/ogg',
    ];
    for (const type of types) {
      if (MediaRecorder.isTypeSupported(type)) return type;
    }
    return ''; // Let browser decide
  };

  const startRecording = async () => {
    setError(null);
    setResult(null);
    setInputText(''); 
    cleanupAudio(); // Ensure clean state

    // 1. Check for Secure Context
    if (window.location.protocol !== 'https:' && window.location.hostname !== 'localhost' && window.location.hostname !== '127.0.0.1') {
         setError("Microphone access requires a secure connection (HTTPS). Please ensure you are viewing this page over https://");
         return;
    }

    // 2. Check Browser Support
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Your browser does not support audio recording. Please use a modern browser (Chrome, Firefox, Safari) and ensure permissions are enabled.");
        return;
    }

    try {
      // --- Start Audio Stream for Visualizer & MediaRecorder ---
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Setup Visualizer
      try {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        analyserRef.current = audioContextRef.current.createAnalyser();
        sourceRef.current = audioContextRef.current.createMediaStreamSource(stream);
        sourceRef.current.connect(analyserRef.current);
        analyserRef.current.fftSize = 256;
        drawVisualizer();
      } catch (audioCtxError) {
        console.warn("Visualizer setup failed, continuing with recording only:", audioCtxError);
      }

      // Setup Media Recorder (For Blob)
      const options = { mimeType: getSupportedMimeType() };
      mediaRecorderRef.current = options.mimeType 
        ? new MediaRecorder(stream, options) 
        : new MediaRecorder(stream);

      setMimeType(mediaRecorderRef.current.mimeType);

      chunksRef.current = [];
      mediaRecorderRef.current.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorderRef.current.onstop = () => {
        const actualMimeType = mediaRecorderRef.current?.mimeType || 'audio/webm';
        const blob = new Blob(chunksRef.current, { type: actualMimeType });
        setAudioBlob(blob);
        setMimeType(actualMimeType);
        const url = URL.createObjectURL(blob);
        setAudioUrl(url);

        // Cleanup stream tracks
        stream.getTracks().forEach(track => track.stop());
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      };

      mediaRecorderRef.current.start();

      // --- Start Web Speech API for Immediate Text Extraction ---
      if ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;
        recognitionRef.current.lang = 'en-US';

        recognitionRef.current.onresult = (event: any) => {
          let finalTranscript = '';
          for (let i = event.resultIndex; i < event.results.length; ++i) {
            if (event.results[i].isFinal) {
              finalTranscript += event.results[i][0].transcript;
            } else {
               // Optional: You could show interim results differently
               // finalTranscript += event.results[i][0].transcript; 
            }
          }
          // We prefer just grabbing the latest transcript to update state
          const currentTranscript = Array.from(event.results)
            .map((result: any) => result[0].transcript)
            .join('');

          setInputText(currentTranscript);
        };

        recognitionRef.current.onerror = (event: any) => {
          console.warn("Speech recognition error", event.error);
        };

        recognitionRef.current.start();
      }

      setIsRecording(true);
      setRecordingDuration(0);

      timerRef.current = window.setInterval(() => {
        setRecordingDuration(prev => prev + 1);
      }, 1000);

    } catch (err: any) {
      console.error("Error accessing microphone:", err);

      // Friendly Error Messages
      let msg = "Could not access microphone.";
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
          msg = "Permission denied. Please click the lock icon in your browser address bar, allow Microphone access, and reload the page.";
      } else if (err.name === 'NotFoundError') {
          msg = "No microphone found. Please check your device connections.";
      } else if (err.name === 'NotReadableError') {
          msg = "Microphone is busy. Is another application (Zoom, Teams, etc.) using it?";
      } else {
          msg = `Microphone Error: ${err.message || "Unknown error"}`;
      }

      setError(msg);
    }
  };

  const stopAndAnalyze = async () => {
    // Stop Recognition
    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }

    // Stop Recorder
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) clearInterval(timerRef.current);

      // Short delay to allow onstop to fire and blob to settle
      setLoading(true);
      setTimeout(() => {
        handlePredict(true); // true = called from stop
      }, 500);
    }
  };

  const clearAudio = () => {
    setAudioBlob(null);
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setAudioUrl(null);
    setRecordingDuration(0);
    setResult(null);
    setInputText('');
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        const base64 = base64String.split(',')[1];
        resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(blob);
    });
  };

  const handlePredict = async (isAuto = false) => {
    // If we have text from Web Speech API, use it? 
    // The requirement says "Text should be extracted... and provide Hate/Offensive".
    // We send audio for Multimodal analysis (better accuracy on tone), but we display the text.

    if (!inputText.trim() && !audioBlob && !chunksRef.current.length) return;

    setLoading(true);
    setError(null);
    if (!isAuto) setResult(null);

    try {
      let audioData = undefined;

      let blobToUse = audioBlob;
      if (!blobToUse && chunksRef.current.length > 0) {
        blobToUse = new Blob(chunksRef.current, { type: mimeType });
      }

      if (blobToUse) {
        const base64 = await blobToBase64(blobToUse);
        audioData = {
          data: base64,
          mimeType: blobToUse.type || mimeType
        };
      }

      // We send both InputText (from Web Speech) and Audio.
      // However, if we send audio, the backend prioritizes audio transcription.
      const prediction = await analyzeText(inputText, audioData);

      setResult(prediction);

      // If the model returned a refined transcription from the audio, update the UI
      if (prediction.transcription && prediction.transcription.length > 5) {
          setInputText(prediction.transcription);
      }

    } catch (err: any) {
      console.error("Caught error in Demo:", err);
      const errorMessage = err.message || "Unknown error occurred.";
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const getResultColor = (label: ClassLabel) => {
    switch (label) {
      case ClassLabel.HATE_SPEECH: return 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-900 dark:text-red-200';
      case ClassLabel.OFFENSIVE_LANGUAGE: return 'bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800 text-amber-900 dark:text-amber-200';
      case ClassLabel.NORMAL: return 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800 text-green-900 dark:text-green-200';
      default: return 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700';
    }
  };

  const getResultIcon = (label: ClassLabel) => {
    switch (label) {
      case ClassLabel.HATE_SPEECH: return <AlertTriangle className="h-6 w-6 text-red-600 dark:text-red-400" />;
      case ClassLabel.OFFENSIVE_LANGUAGE: return <Info className="h-6 w-6 text-amber-600 dark:text-amber-400" />;
      case ClassLabel.NORMAL: return <CheckCircle className="h-6 w-6 text-green-600 dark:text-green-400" />;
      default: return null;
    }
  };

  return (
    <div className="max-w-3xl mx-auto py-12 px-4">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-white">Live Multimodal Demo</h2>
        <p className="text-slate-500 mt-2">Speak naturally or type text to test the OLS classifier.</p>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl shadow-lg border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">

        {/* Mode Selector / Input Area */}
        <div className="p-6 space-y-6">

          {/* Audio Input Section */}
          <div>
            <div className="flex justify-between items-center mb-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                Voice Input (Live)
                </label>
                {isRecording && <span className="flex items-center text-xs text-red-500 animate-pulse font-bold"><div className="h-2 w-2 bg-red-500 rounded-full mr-1"></div> RECORDING</span>}
